solution_code:
#include <iostream>

int main()
{
    int arr[8]{};
    int n{};
    std::cin >> n;

    for (int i{ 0 }; i < n; ++i)
    {
        std::cin >> arr[i];
    }

    for (int i{ n - 1 }; i >= 0; --i)
    {
        if (i < n - 1)
            std::cout << ' ';
        std::cout << arr[i];
    }
    std::cout << '\n';

    std::cout << sizeof(arr) << '\n';
    std::cout << sizeof(arr) / sizeof(arr[0]) << '\n';

    return 0;
}
